#!/usr/bin/env python3 """ inference_queue.py - Observable FIFO buffers for single-GPU Qwythos (:8090). Two physical drain lanes on :8091: lane 0 (roleplay) - drained before lane 1 lane 1 (normal) - priority-ordered: interactive, then normal, then background Logical priority classes (within normal lane ordering): interactive - user/discord/API sessions (not background markers) normal - general agent work without background markers background - cron, inbox, guardian, procurement (deferred when RP hot) Poll GET /v1/queue or /v1/queue/{id}. Completions include X-Phronesis-Queue-* headers. Watchdog auto-heals when the active job or upstream port looks stuck. """ from __future__ import annotations import json import os import socket import threading import time import uuid from collections import deque from dataclasses import asdict, dataclass, field from datetime import datetime, timezone from typing import Any, Deque, Dict, List, Optional LANE_ROLEPLAY = 0 LANE_NORMAL = 1 PRIORITY_INTERACTIVE = "interactive" PRIORITY_NORMAL = "normal" PRIORITY_BACKGROUND = "background" PRIORITY_CLASSES = (PRIORITY_INTERACTIVE, PRIORITY_NORMAL, PRIORITY_BACKGROUND) PRIORITY_ETA_WEIGHT = { PRIORITY_INTERACTIVE: 0.85, PRIORITY_NORMAL: 1.0, PRIORITY_BACKGROUND: 1.15, } STUCK_WARN_SEC = 900 STUCK_HEAL_SEC = 1680 MAX_QUEUE_WAIT_SEC = 1800 STATE_PERSIST_INTERVAL_SEC = 5.0 HEAL_COOLDOWN_SEC = 180 WATCHDOG_INTERVAL_SEC = 15 LATENCY_HISTORY_MAX = 48 DONE_HISTORY_MAX = 32 MAX_NORMAL_DEPTH_WHEN_RP_BUSY = 4 MAX_INTERACTIVE_FIFO_DEPTH = 10 ADMISSION_REJECT_RETRY_SEC = 90 BACKGROUND_DEFER_RETRY_SEC = 120 BACKGROUND_CALLER_MARKERS = ( "cron", "grok-inbox", "grok_inbox", "backup", "procurement", "benchmark", "guardian", "inbox", "fleet_procurement", "resilience", ) STATE_FILE = r"D:\PhronesisVault\Operations\logs\inference-queue-state.json" COMFY_RENDER_LOCK = r"D:\HermesData\state\roleplay-render.lock" COMFY_LOCK_STALE_SEC = 1800 COMFY_YIELD_FIFO_DEPTH = 3 COMFY_YIELD_INTERACTIVE_WAITING = 2 COMFY_YIELD_VRAM_PCT = 88.0 class QueueWaitTimeout(Exception): def __init__(self, entry: "QueueEntry"): self.entry = entry super().__init__( f"FIFO wait exceeded {MAX_QUEUE_WAIT_SEC}s (position {entry.position}, lane {entry.lane})" ) class BackgroundDeferred(Exception): """Low-priority caller rejected while roleplay or deep queue pressure is active.""" def __init__(self, reason: str, retry_after_sec: int = BACKGROUND_DEFER_RETRY_SEC): self.reason = reason self.retry_after_sec = retry_after_sec super().__init__(reason) class QueueAdmissionRejected(Exception): """Interactive caller rejected at FIFO gate -- queue too deep to admit.""" def __init__(self, reason: str, *, waiting_count: int, retry_after_sec: int = ADMISSION_REJECT_RETRY_SEC): self.reason = reason self.waiting_count = waiting_count self.retry_after_sec = retry_after_sec super().__init__(reason) @dataclass class QueueEntry: id: str model: str caller: str lane: int priority_class: str = PRIORITY_NORMAL state: str = "waiting" enqueued_at: float = field(default_factory=time.time) started_at: Optional[float] = None finished_at: Optional[float] = None position: int = 0 wait_sec: float = 0.0 run_sec: Optional[float] = None error: Optional[str] = None eta_sec: Optional[float] = None prompt_tokens_est: Optional[int] = None message_count: Optional[int] = None max_tokens: Optional[int] = None def to_dict(self) -> Dict[str, Any]: now = time.time() d = asdict(self) d["lane_name"] = "roleplay" if self.lane == LANE_ROLEPLAY else "normal" d["enqueued_at_iso"] = datetime.fromtimestamp(self.enqueued_at, tz=timezone.utc).isoformat() if self.state == "waiting": d["wait_so_far_sec"] = round(now - self.enqueued_at, 1) elif self.state == "running" and self.started_at: d["run_so_far_sec"] = round(now - self.started_at, 1) if self.eta_sec is not None: d["weighted_eta_sec"] = self.eta_sec return d class InferenceQueue: """Two-lane FIFO gate: roleplay buffer first, then normal buffer.""" def __init__(self) -> None: self._lock = threading.Condition(threading.Lock()) self._lanes: Dict[int, Deque[QueueEntry]] = { LANE_ROLEPLAY: deque(), LANE_NORMAL: deque(), } self._active: Optional[QueueEntry] = None self._done: Deque[QueueEntry] = deque(maxlen=DONE_HISTORY_MAX) self._latencies: Deque[float] = deque(maxlen=LATENCY_HISTORY_MAX) self._last_heal_at = 0.0 self._heal_in_progress = False self._watchdog_started = False self._last_persist_at = 0.0 self._stats = { "total_enqueued": 0, "total_completed": 0, "total_failed": 0, "total_heals": 0, "last_heal_at": None, "last_stuck_warn_at": None, } def _avg_latency(self) -> float: if not self._latencies: return 45.0 return sum(self._latencies) / len(self._latencies) def _est_job_sec(self, entry: QueueEntry) -> float: """Token-weighted ETA with priority class multiplier (TNG fair-queue pattern).""" base = self._avg_latency() tokens = float(entry.prompt_tokens_est or 4096) max_out = float(entry.max_tokens or 2048) scale = max(0.45, min(3.5, (tokens / 8192.0) + (max_out / 4096.0) * 0.45)) weight = PRIORITY_ETA_WEIGHT.get(entry.priority_class, 1.0) return base * scale * weight def _rp_lane_busy(self) -> bool: if self._lanes[LANE_ROLEPLAY]: return True return bool(self._active and self._active.lane == LANE_ROLEPLAY) def _flatten_waiting(self) -> List[QueueEntry]: return list(self._lanes[LANE_ROLEPLAY]) + list(self._lanes[LANE_NORMAL]) def _refresh_positions(self) -> None: pos = 1 active_remain = 0.0 if self._active and self._active.started_at: elapsed = time.time() - self._active.started_at active_remain = max(0.0, self._est_job_sec(self._active) - elapsed) ahead_sec = active_remain for lane in (LANE_ROLEPLAY, LANE_NORMAL): for entry in self._lanes[lane]: entry.position = pos entry.eta_sec = round(ahead_sec, 1) ahead_sec += self._est_job_sec(entry) pos += 1 def resolve_lane(self, model: str, routing: Optional[Dict[str, Any]] = None) -> int: routing = routing or {} m = (model or "").lower() if routing.get("force_roleplay") or "roleplay" in m: return LANE_ROLEPLAY return LANE_NORMAL def _enqueue(self, lane_id: int, entry: QueueEntry) -> None: if lane_id == LANE_NORMAL: _insert_by_priority(self._lanes[LANE_NORMAL], entry) else: self._lanes[lane_id].append(entry) def _peek_next(self) -> Optional[QueueEntry]: if self._lanes[LANE_ROLEPLAY]: return self._lanes[LANE_ROLEPLAY][0] if self._lanes[LANE_NORMAL]: return self._lanes[LANE_NORMAL][0] return None def _pop_next(self) -> Optional[QueueEntry]: if self._lanes[LANE_ROLEPLAY]: return self._lanes[LANE_ROLEPLAY].popleft() if self._lanes[LANE_NORMAL]: return self._lanes[LANE_NORMAL].popleft() return None def _remove_from_lanes(self, entry_id: str) -> Optional[QueueEntry]: for lane in (LANE_ROLEPLAY, LANE_NORMAL): for idx, entry in enumerate(self._lanes[lane]): if entry.id == entry_id: del self._lanes[lane][idx] self._refresh_positions() return entry return None def acquire( self, *, model: str, caller: str = "unknown", lane: Optional[int] = None, request_id: Optional[str] = None, routing: Optional[Dict[str, Any]] = None, prompt_tokens_est: Optional[int] = None, message_count: Optional[int] = None, max_tokens: Optional[int] = None, ) -> QueueEntry: lane_id = lane if lane is not None else self.resolve_lane(model, routing) with self._lock: rp_busy = self._rp_lane_busy() normal_depth = len(self._lanes[LANE_NORMAL]) rp_depth = len(self._lanes[LANE_ROLEPLAY]) waiting_total = normal_depth + rp_depth + (1 if self._active else 0) if lane_id == LANE_NORMAL and _is_background_caller(caller): if rp_busy and normal_depth >= MAX_NORMAL_DEPTH_WHEN_RP_BUSY: raise BackgroundDeferred( f"roleplay_busy_normal_depth_{normal_depth}", retry_after_sec=BACKGROUND_DEFER_RETRY_SEC, ) if waiting_total >= 8: raise BackgroundDeferred( f"queue_pressure_{waiting_total}", retry_after_sec=BACKGROUND_DEFER_RETRY_SEC, ) if ( lane_id == LANE_NORMAL and _is_interactive_caller(caller, lane_id) and waiting_total >= MAX_INTERACTIVE_FIFO_DEPTH ): raise QueueAdmissionRejected( f"fifo_depth_{waiting_total}", waiting_count=waiting_total, retry_after_sec=ADMISSION_REJECT_RETRY_SEC, ) entry = QueueEntry( id=request_id or f"inf_{uuid.uuid4().hex[:12]}", model=model, caller=caller[:120], lane=lane_id, priority_class=resolve_priority_class(caller, lane_id), prompt_tokens_est=prompt_tokens_est, message_count=message_count, max_tokens=max_tokens, ) with self._lock: self._stats["total_enqueued"] += 1 self._enqueue(lane_id, entry) self._refresh_positions() self._persist_state_unlocked() while True: nxt = self._peek_next() if self._active is None and nxt and nxt.id == entry.id: if comfy_render_lock_active(): self._refresh_positions() self._lock.wait(timeout=2.0) if time.time() - entry.enqueued_at > MAX_QUEUE_WAIT_SEC: removed = self._remove_from_lanes(entry.id) if removed: removed.state = "failed" removed.error = "fifo_wait_comfy_render" removed.finished_at = time.time() self._done.appendleft(removed) self._stats["total_failed"] += 1 self._persist_state_unlocked(force=True) raise QueueWaitTimeout(removed) continue self._pop_next() self._active = entry entry.state = "running" entry.started_at = time.time() entry.wait_sec = round(entry.started_at - entry.enqueued_at, 2) entry.position = 0 self._refresh_positions() self._persist_state_unlocked(force=True) return entry if time.time() - entry.enqueued_at > MAX_QUEUE_WAIT_SEC: removed = self._remove_from_lanes(entry.id) if removed: removed.state = "failed" removed.error = "fifo_wait_timeout" removed.finished_at = time.time() self._done.appendleft(removed) self._stats["total_failed"] += 1 self._persist_state_unlocked(force=True) raise QueueWaitTimeout(removed) self._refresh_positions() self._lock.wait(timeout=2.0) def release( self, request_id: str, *, success: bool = True, error: Optional[str] = None, latency_sec: Optional[float] = None, ) -> None: with self._lock: if not self._active or self._active.id != request_id: return entry = self._active entry.finished_at = time.time() entry.state = "done" if success else "failed" entry.error = error if entry.started_at: entry.run_sec = round(entry.finished_at - entry.started_at, 2) if latency_sec is not None and success: self._latencies.append(float(latency_sec)) elif entry.run_sec is not None and success: self._latencies.append(entry.run_sec) self._done.appendleft(entry) self._active = None if success: self._stats["total_completed"] += 1 else: self._stats["total_failed"] += 1 self._persist_state_unlocked(force=True) self._lock.notify_all() def get(self, request_id: str) -> Optional[Dict[str, Any]]: with self._lock: if self._active and self._active.id == request_id: return self._active.to_dict() for entry in self._flatten_waiting(): if entry.id == request_id: return entry.to_dict() for entry in self._done: if entry.id == request_id: return entry.to_dict() return None def _priority_lane_snapshot(self) -> Dict[str, Any]: buckets: Dict[str, List[Dict[str, Any]]] = { PRIORITY_INTERACTIVE: [], PRIORITY_NORMAL: [], PRIORITY_BACKGROUND: [], } for entry in self._flatten_waiting(): key = entry.priority_class if entry.priority_class in buckets else PRIORITY_NORMAL buckets[key].append(entry.to_dict()) return { prio: { "priority": prio, "policy": "weighted_fifo", "count": len(items), "waiting": items, } for prio, items in buckets.items() } def snapshot(self) -> Dict[str, Any]: with self._lock: waiting_count = len(self._lanes[LANE_ROLEPLAY]) + len(self._lanes[LANE_NORMAL]) active_count = 1 if self._active else 0 priority_lanes = self._priority_lane_snapshot() prio_counts = {prio: int(lane.get("count") or 0) for prio, lane in priority_lanes.items()} return { "timestamp": datetime.now(timezone.utc).isoformat(), "fifo_lanes": { "roleplay": { "lane": LANE_ROLEPLAY, "policy": "strict_fifo", "waiting": [e.to_dict() for e in self._lanes[LANE_ROLEPLAY]], "count": len(self._lanes[LANE_ROLEPLAY]), }, "normal": { "lane": LANE_NORMAL, "policy": "priority_fifo", "waiting": [e.to_dict() for e in self._lanes[LANE_NORMAL]], "count": len(self._lanes[LANE_NORMAL]), }, }, "priority_lanes": priority_lanes, "priority_counts": prio_counts, "avg_latency_sec": round(self._avg_latency(), 1), "active": self._active.to_dict() if self._active else None, "active_priority_class": ( self._active.priority_class if self._active else None ), "waiting_count": waiting_count, "recent_done": [e.to_dict() for e in list(self._done)[:8]], "stats": dict(self._stats), "thresholds": { "stuck_warn_sec": STUCK_WARN_SEC, "stuck_heal_sec": STUCK_HEAL_SEC, "max_fifo_wait_sec": MAX_QUEUE_WAIT_SEC, "max_interactive_depth": MAX_INTERACTIVE_FIFO_DEPTH, "admission_retry_sec": ADMISSION_REJECT_RETRY_SEC, "priority_eta_weight": PRIORITY_ETA_WEIGHT, }, "admission": { "waiting_count": waiting_count, "active_count": active_count, "total_pressure": waiting_count + active_count, "roleplay_waiting": len(self._lanes[LANE_ROLEPLAY]), "interactive_waiting": prio_counts.get(PRIORITY_INTERACTIVE, 0), "normal_waiting": prio_counts.get(PRIORITY_NORMAL, 0), "background_waiting": prio_counts.get(PRIORITY_BACKGROUND, 0), "max_interactive_depth": MAX_INTERACTIVE_FIFO_DEPTH, "priority_classes": list(PRIORITY_CLASSES), "pressure_tier": fifo_pressure_tier( waiting_count, prio_counts.get(PRIORITY_INTERACTIVE, 0), ), }, "comfy_yield": _comfy_yield_fields( waiting_count=waiting_count, interactive_waiting=prio_counts.get(PRIORITY_INTERACTIVE, 0), active=bool(self._active), rp_waiting=len(self._lanes[LANE_ROLEPLAY]), ), } def _persist_state_unlocked(self, *, force: bool = False) -> None: now = time.time() if not force and (now - self._last_persist_at) < STATE_PERSIST_INTERVAL_SEC: return self._last_persist_at = now try: from pathlib import Path snap = { "timestamp": datetime.now(timezone.utc).isoformat(), "fifo_lanes": { "roleplay": [e.to_dict() for e in self._lanes[LANE_ROLEPLAY]], "normal": [e.to_dict() for e in self._lanes[LANE_NORMAL]], }, "active": self._active.to_dict() if self._active else None, "stats": dict(self._stats), } path = Path(STATE_FILE) path.parent.mkdir(parents=True, exist_ok=True) path.write_text(json.dumps(snap, indent=2), encoding="utf-8") except Exception: pass def _port_up(self, port: int) -> bool: try: with socket.create_connection(("127.0.0.1", port), timeout=0.5): return True except OSError: return False def _maybe_heal(self, reason: str) -> Dict[str, Any]: now = time.time() if self._heal_in_progress or (now - self._last_heal_at) < HEAL_COOLDOWN_SEC: return {"skipped": True, "reason": "cooldown_or_in_progress"} self._heal_in_progress = True self._last_heal_at = now result: Dict[str, Any] = {"reason": reason, "recoveries": []} try: from model_resource_manager import ( append_watchdog_log, attempt_moe_recovery, attempt_proxy_recovery, ) if not self._port_up(8090): result["recoveries"].append({"target": "8090", **attempt_moe_recovery()}) elif not self._port_up(8091): result["recoveries"].append({"target": "8091", **attempt_proxy_recovery()}) else: result["recoveries"].append({"target": "8090_stuck", **attempt_moe_recovery()}) self._stats["total_heals"] += 1 self._stats["last_heal_at"] = datetime.now(timezone.utc).isoformat() append_watchdog_log({"event": "inference_queue_heal", **result}) except Exception as exc: result["error"] = str(exc) finally: self._heal_in_progress = False return result def _watchdog_tick(self) -> None: heal_reason: Optional[str] = None with self._lock: active = self._active waiting_count = len(self._lanes[LANE_ROLEPLAY]) + len(self._lanes[LANE_NORMAL]) if not active or not active.started_at: if waiting_count > 0 and not self._port_up(8090): heal_reason = "8090_down_with_waiters" if heal_reason: self._maybe_heal(heal_reason) return run_so_far = time.time() - active.started_at if run_so_far >= STUCK_HEAL_SEC: heal_reason = f"active_exceeded_{STUCK_HEAL_SEC}s" elif run_so_far >= STUCK_WARN_SEC: with self._lock: self._stats["last_stuck_warn_at"] = datetime.now(timezone.utc).isoformat() try: from model_resource_manager import append_watchdog_log append_watchdog_log({ "event": "inference_queue_stuck_warn", "request_id": active.id, "model": active.model, "caller": active.caller, "run_so_far_sec": round(run_so_far, 1), "waiting_count": waiting_count, }) except Exception: pass if waiting_count > 2 and run_so_far >= STUCK_HEAL_SEC * 0.85: heal_reason = f"active_slow_with_{waiting_count}_waiters" if heal_reason: self._maybe_heal(heal_reason) def start_watchdog(self) -> None: if self._watchdog_started: return self._watchdog_started = True def _loop() -> None: while True: try: self._watchdog_tick() except Exception: pass time.sleep(WATCHDOG_INTERVAL_SEC) threading.Thread(target=_loop, name="inference-queue-watchdog", daemon=True).start() _QUEUE: Optional[InferenceQueue] = None _QUEUE_LOCK = threading.Lock() def _is_background_caller(caller: str) -> bool: c = (caller or "").lower() return any(marker in c for marker in BACKGROUND_CALLER_MARKERS) def _is_interactive_caller(caller: str, lane_id: int) -> bool: if lane_id == LANE_ROLEPLAY: return True return not _is_background_caller(caller) def resolve_priority_class(caller: str, lane_id: int) -> str: """Map caller + lane to interactive | normal | background.""" if lane_id == LANE_ROLEPLAY: return PRIORITY_INTERACTIVE if _is_background_caller(caller): return PRIORITY_BACKGROUND if _is_interactive_caller(caller, lane_id): return PRIORITY_INTERACTIVE return PRIORITY_NORMAL def _priority_rank(priority_class: str) -> int: order = { PRIORITY_INTERACTIVE: 0, PRIORITY_NORMAL: 1, PRIORITY_BACKGROUND: 2, } return order.get(priority_class, 1) def _insert_by_priority(lane: Deque[QueueEntry], entry: QueueEntry) -> None: """Insert into normal lane: interactive first, normal middle, background last.""" rank = _priority_rank(entry.priority_class) insert_at = len(lane) for idx, existing in enumerate(lane): if _priority_rank(existing.priority_class) > rank: insert_at = idx break if insert_at >= len(lane): lane.append(entry) else: lane.insert(insert_at, entry) def admission_snapshot() -> Dict[str, Any]: """Non-blocking FIFO depth for admission policy on :8091.""" snap = get_inference_queue().snapshot() waiting = int(snap.get("waiting_count") or 0) active = 1 if snap.get("active") else 0 rp_waiting = int((snap.get("fifo_lanes") or {}).get("roleplay", {}).get("count") or 0) admission = snap.get("admission") or {} return { "waiting_count": waiting, "active_count": active, "total_pressure": waiting + active, "roleplay_waiting": rp_waiting, "interactive_waiting": int(admission.get("interactive_waiting") or 0), "normal_waiting": int(admission.get("normal_waiting") or 0), "background_waiting": int(admission.get("background_waiting") or 0), "max_interactive_depth": MAX_INTERACTIVE_FIFO_DEPTH, "priority_classes": list(PRIORITY_CLASSES), } def _parse_comfy_lock(raw: str) -> tuple[int, float]: text = (raw or "").strip() if not text: return 0, 0.0 if ":" in text: pid_part, ts_part = text.split(":", 1) try: return int(pid_part.strip()), float(ts_part.strip()) except (TypeError, ValueError): return 0, 0.0 try: return int(text), 0.0 except (TypeError, ValueError): return 0, 0.0 def _pid_alive(pid: int) -> bool: if pid <= 0: return False if os.name != "nt": try: os.kill(pid, 0) return True except OSError: return False import ctypes handle = ctypes.windll.kernel32.OpenProcess(0x1000, False, int(pid)) alive = bool(handle) if handle: ctypes.windll.kernel32.CloseHandle(handle) return alive def cleanup_stale_comfy_lock() -> Dict[str, Any]: """Drop roleplay-render.lock when holder pid is dead or timestamp is stale.""" from pathlib import Path lock = Path(COMFY_RENDER_LOCK) if not lock.is_file(): return {"cleaned": False, "reason": "no_lock"} try: raw = lock.read_text(encoding="utf-8").strip() pid, ts = _parse_comfy_lock(raw) stale_ts = bool(ts and (time.time() - ts) > COMFY_LOCK_STALE_SEC) dead_pid = pid > 0 and not _pid_alive(pid) orphan_pid = pid <= 0 and not ts if stale_ts or dead_pid or orphan_pid: lock.unlink(missing_ok=True) return { "cleaned": True, "reason": "stale_ts" if stale_ts else ("dead_pid" if dead_pid else "orphan_pid"), "pid": pid, } return {"cleaned": False, "reason": "lock_live", "pid": pid} except OSError as exc: return {"cleaned": False, "reason": "os_error", "error": str(exc)[:120]} def comfy_render_lock_active() -> bool: """True while ComfyUI holds the shared GPU render lock.""" from pathlib import Path cleanup = cleanup_stale_comfy_lock() if cleanup.get("cleaned"): return False lock = Path(COMFY_RENDER_LOCK) if not lock.is_file(): return False try: raw = lock.read_text(encoding="utf-8").strip() pid, ts = _parse_comfy_lock(raw) if pid > 0 and not _pid_alive(pid): lock.unlink(missing_ok=True) return False if ts and (time.time() - ts) > COMFY_LOCK_STALE_SEC: lock.unlink(missing_ok=True) return False except OSError: return False except (TypeError, ValueError): pass return True def fifo_pressure_tier(waiting_count: int, interactive_waiting: int = 0) -> str: """cool | warm | hot -- used by Comfy yield and dashboard hints.""" if waiting_count >= COMFY_YIELD_FIFO_DEPTH: return "hot" if interactive_waiting >= COMFY_YIELD_INTERACTIVE_WAITING: return "warm" if waiting_count >= 2: return "warm" return "cool" def _comfy_yield_fields( *, waiting_count: int, interactive_waiting: int, active: bool, rp_waiting: int, ) -> Dict[str, Any]: defer = False reason = "ok" if active: defer, reason = True, "inference_active" elif rp_waiting > 0: defer, reason = True, f"roleplay_waiting_{rp_waiting}" elif waiting_count >= COMFY_YIELD_FIFO_DEPTH: defer, reason = True, f"fifo_depth_{waiting_count}" elif interactive_waiting >= COMFY_YIELD_INTERACTIVE_WAITING: defer, reason = True, f"interactive_waiting_{interactive_waiting}" return { "defer_comfy": defer, "reason": reason, "fifo_depth": waiting_count, "interactive_waiting": interactive_waiting, "pressure_tier": fifo_pressure_tier(waiting_count, interactive_waiting), "yield_threshold_depth": COMFY_YIELD_FIFO_DEPTH, "yield_threshold_vram_pct": COMFY_YIELD_VRAM_PCT, "lock_active": comfy_render_lock_active(), } def comfy_yield_snapshot() -> Dict[str, Any]: """Comfy defer policy snapshot for tile + warm_tier_actions.""" cleanup_stale_comfy_lock() snap = get_inference_queue().snapshot() admission = snap.get("admission") or {} rp_waiting = int((snap.get("fifo_lanes") or {}).get("roleplay", {}).get("count") or 0) return _comfy_yield_fields( waiting_count=int(snap.get("waiting_count") or 0), interactive_waiting=int(admission.get("interactive_waiting") or 0), active=bool(snap.get("active")), rp_waiting=rp_waiting, ) def should_defer_comfy_render() -> tuple[bool, str]: """Defer ComfyUI when Qwythos inference owns, RP waits, or FIFO depth is hot.""" snap = get_inference_queue().snapshot() if snap.get("active"): return True, "inference_active" rp_waiting = int((snap.get("fifo_lanes") or {}).get("roleplay", {}).get("count") or 0) if rp_waiting > 0: return True, f"roleplay_waiting_{rp_waiting}" waiting = int(snap.get("waiting_count") or 0) admission = snap.get("admission") or {} interactive = int(admission.get("interactive_waiting") or 0) if waiting >= COMFY_YIELD_FIFO_DEPTH: return True, f"fifo_depth_{waiting}" if interactive >= COMFY_YIELD_INTERACTIVE_WAITING: return True, f"interactive_waiting_{interactive}" return False, "ok" def should_defer_background_work() -> tuple[bool, str]: """Shared gate for cron/inbox consumers defer when RP owns or waits on GPU.""" q = get_inference_queue() snap = q.snapshot() active = snap.get("active") or {} rp_waiting = int((snap.get("fifo_lanes") or {}).get("roleplay", {}).get("count") or 0) if active.get("lane_name") == "roleplay" or active.get("lane") == LANE_ROLEPLAY: return True, "roleplay_active" if rp_waiting > 0: return True, f"roleplay_waiting_{rp_waiting}" waiting = int(snap.get("waiting_count") or 0) if waiting >= 6: return True, f"fifo_depth_{waiting}" return False, "ok" def should_defer_proactive_offload() -> tuple[bool, str]: """Defer T2/T3 proactive offload while GPU FIFO is hot (RP or deep queue).""" q = get_inference_queue() snap = q.snapshot() active = snap.get("active") or {} rp_waiting = int((snap.get("fifo_lanes") or {}).get("roleplay", {}).get("count") or 0) normal_waiting = int((snap.get("fifo_lanes") or {}).get("normal", {}).get("count") or 0) if active.get("lane_name") == "roleplay" or active.get("lane") == LANE_ROLEPLAY: return True, "roleplay_active" if rp_waiting > 0: return True, f"roleplay_waiting_{rp_waiting}" if active and normal_waiting >= 2: return True, f"normal_backlog_{normal_waiting}" waiting = int(snap.get("waiting_count") or 0) if waiting >= 4: return True, f"fifo_depth_{waiting}" return False, "ok" def get_inference_queue() -> InferenceQueue: global _QUEUE with _QUEUE_LOCK: if _QUEUE is None: _QUEUE = InferenceQueue() _QUEUE.start_watchdog() return _QUEUE